package main
import("crypto/ed25519";"crypto/sha256";"encoding/base64";"encoding/hex";"encoding/json";"fmt";"os")
type Key struct{KeyID string `json:"key_id"`;Issuer string `json:"issuer"`;Algorithm string `json:"algorithm"`;PublicKey string `json:"public_key"`;ValidFrom string `json:"valid_from"`;ValidUntil string `json:"valid_until"`;RevokedAt *string `json:"revoked_at"`}
type V struct{Envelope map[string]interface{} `json:"envelope"`;Keyring []Key `json:"keyring"`;VerificationTime string `json:"verification_time"`;SeenNonces []string `json:"seen_nonces"`}
type R struct{Accepted bool `json:"accepted"`;EnvelopeID interface{} `json:"envelope_id"`;ErrorCodes []string `json:"error_codes"`;Issuer interface{} `json:"issuer"`;KeyID interface{} `json:"key_id"`;ObjectType interface{} `json:"object_type"`;PayloadDigest string `json:"payload_digest"`;ReplayToken string `json:"replay_token"`}
func s(m map[string]interface{},k string)string{if v,ok:=m[k].(string);ok{return v};return ""}
func has(xs []string,x string)bool{for _,v:=range xs{if v==x{return true}};return false}
func main(){if len(os.Args)!=3{fmt.Println("usage");os.Exit(2)};b,_:=os.ReadFile(os.Args[1]);var v V;json.Unmarshal(b,&v);e:=v.Envelope;errs:=[]string{};req:=[]string{"envelope_id","object_type","issuer","key_id","issued_at","expires_at","nonce","payload","signature"};miss:=[]string{};for _,k:=range req{if _,ok:=e[k];!ok{miss=append(miss,k)}};if len(miss)>0{errs=append(errs,"MISSING_FIELDS")};var key *Key;for i:=range v.Keyring{if v.Keyring[i].KeyID==s(e,"key_id")&&v.Keyring[i].Issuer==s(e,"issuer"){key=&v.Keyring[i]}};if len(errs)==0&&key==nil{errs=append(errs,"UNKNOWN_KEY")};if len(errs)==0&&key.Algorithm!="Ed25519"{errs=append(errs,"UNSUPPORTED_ALGORITHM")};if len(errs)==0&&key.RevokedAt!=nil&&*key.RevokedAt<=v.VerificationTime{errs=append(errs,"KEY_REVOKED")};if len(errs)==0&&key.ValidFrom!=""&&v.VerificationTime<key.ValidFrom{errs=append(errs,"KEY_NOT_YET_VALID")};if len(errs)==0&&key.ValidUntil!=""&&v.VerificationTime>key.ValidUntil{errs=append(errs,"KEY_EXPIRED")};if len(errs)==0&&v.VerificationTime<s(e,"issued_at"){errs=append(errs,"ENVELOPE_NOT_YET_VALID")};if len(errs)==0&&v.VerificationTime>s(e,"expires_at"){errs=append(errs,"ENVELOPE_EXPIRED")};replay:=s(e,"issuer")+"|"+s(e,"nonce");if len(errs)==0&&has(v.SeenNonces,replay){errs=append(errs,"REPLAY_DETECTED")};sigobj:=map[string]interface{}{};for k,x:=range e{if k!="signature"{sigobj[k]=x}};if len(errs)==0{pub,a:=base64.StdEncoding.DecodeString(key.PublicKey);sig,b:=base64.StdEncoding.DecodeString(s(e,"signature"));msg,_:=json.Marshal(sigobj);if a!=nil||b!=nil||!ed25519.Verify(pub,msg,sig){errs=append(errs,"INVALID_SIGNATURE")}};pb,_:=json.Marshal(e["payload"]);h:=sha256.Sum256(pb);r:=R{len(errs)==0,e["envelope_id"],errs,e["issuer"],e["key_id"],e["object_type"],"sha256:"+hex.EncodeToString(h[:]),replay};out,_:=json.Marshal(r);out=append(out,'\n');os.WriteFile(os.Args[2],out,0644)}
